import{V as e,Z as t,et as n,mt as r,tt as i}from"./chunks/framework.DKmNYlsm.js";var a=JSON.parse(`{"title":"CoMote","description":"","frontmatter":{},"headers":[],"relativePath":"comote/description.md","filePath":"comote/description.md"}`),o={name:`comote/description.md`};function s(e,a,o,s,c,l){return r(),n(`div`,null,[...a[0]||=[i(`<h1 id="comote" tabindex="-1">CoMote <a class="header-anchor" href="#comote" aria-label="Permalink to ‚ÄúCoMote‚Äù">‚Äã</a></h1><p>CoMote is a smartphone applications (iOS and Android) that allows for streaming motion data (accelerometer, gyroscope, etc.) from the smartphone to desktop applications using either the OSC protocol or Websockets. The network&#39;s setup is facilitated by the use of a QR code generated by the targeted remote application receiving the motion sensor data.</p><p><a class="appstore" href="https://apps.apple.com/fr/app/como-te/id1623566703" target="_blank"></a><a class="playstore" href="https://play.google.com/store/apps/details?id=fr.ircam.ismm.comote" target="_blank"></a></p><p>CoMote is especially designed for the CoMo applications family that enables real-time interaction between gestures/movements and sounds. Nevertheless, the CoMote application can be used with any software that makes use of the OSC protocol.</p><p>CoMote and the CoMo applications are software designed and developed by IRCAM in the Sound-Music-Movement-Interaction team (UMR STMS).</p><h2 id="demo" tabindex="-1">Demo <a class="header-anchor" href="#demo" aria-label="Permalink to ‚ÄúDemo‚Äù">‚Äã</a></h2>`,6),t(`div`,{style:{position:`relative`,width:`100%`,height:`0`,"padding-bottom":`56.25%`}},[t(`iframe`,{style:{position:`absolute`,top:`0`,left:`0`,width:`100%`,height:`100%`},src:`https://www.youtube.com/embed/YP3ZCP9hsb8`,title:`CoMote demo`,frameborder:`0`,allowfullscreen:``})],-1),i(`<h2 id="technical-details" tabindex="-1">Technical details <a class="header-anchor" href="#technical-details" aria-label="Permalink to ‚ÄúTechnical details‚Äù">‚Äã</a></h2><p>The CoMote application is open-source and available on Github: <a href="https://github.com/ircam-ismm/comote" target="_blank" rel="noreferrer">https://github.com/ircam-ismm/comote</a>.</p><h3 id="sensor-format" tabindex="-1">Sensor format <a class="header-anchor" href="#sensor-format" aria-label="Permalink to ‚ÄúSensor format‚Äù">‚Äã</a></h3><p>One of the main goal of the application is to provide unified axis and units across the different platforms. For this reason, we choose to follow a specification derived from Web Standards that is described in the <a href="./../format/v3.html">sensors data format</a></p><h3 id="integration" tabindex="-1">Integration <a class="header-anchor" href="#integration" aria-label="Permalink to ‚ÄúIntegration‚Äù">‚Äã</a></h3><p>To integrate the CoMote application within your own application, we provide 2 different related packages for Node.js and Max/MSP. You can find more information on our dedicated github repository <a href="https://github.com/ircam-ismm/comote-helpers" target="_blank" rel="noreferrer">https://github.com/ircam-ismm/comote-helpers</a>.</p><p>The Max/MSP package can be directly downloaded at the following url <a href="https://github.com/ircam-ismm/comote-helpers/releases/latest/" target="_blank" rel="noreferrer">https://github.com/ircam-ismm/comote-helpers/releases/latest/</a></p><h2 id="credits" tabindex="-1">Credits <a class="header-anchor" href="#credits" aria-label="Permalink to ‚ÄúCredits‚Äù">‚Äã</a></h2><p>CoMote and the KORAL extension are developed by the STMS-Lab (Ircam-CNRS-Sorbonne Universit√©-Minist√®re de la Culture) in partnership with the Arts Convergences association.</p><p>With the support of: Fondation MAAF, Fondation Falret, D√©partement des Yvelines and Foundation Afnic (Fondation de France).</p><p>Until version 1.2 CoMote was supported by: √âducation Nationale (Edu-up) and Agence Nationale de la Recherche (ELEMENT project).</p><h2 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to ‚ÄúPrivacy Policy‚Äù">‚Äã</a></h2><p><a href="https://ismm-apps.ircam.fr/comote-privacy-policy" target="_blank" rel="noreferrer">https://ismm-apps.ircam.fr/comote-privacy-policy</a></p>`,13)]])}var c=e(o,[[`render`,s]]);export{a as __pageData,c as default};